static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    Conv2dScalingMinCustomTilingData tiling;

    const gert::Shape* x_shape = context->GetInputShape(0);
    const gert::Shape* w_shape = context->GetInputShape(1);

    const auto& x_ori = x_shape->GetOriginShape();
    const auto& w_ori = w_shape->GetOriginShape();

    const uint32_t N  = static_cast<uint32_t>(x_ori.GetDim(0));
    const uint32_t Cin = static_cast<uint32_t>(x_ori.GetDim(1));
    const uint32_t H  = static_cast<uint32_t>(x_ori.GetDim(2));
    const uint32_t W  = static_cast<uint32_t>(x_ori.GetDim(3));

    const uint32_t Cout = static_cast<uint32_t>(w_ori.GetDim(0));
    const uint32_t KCin = static_cast<uint32_t>(w_ori.GetDim(1));
    const uint32_t Kh = static_cast<uint32_t>(w_ori.GetDim(2));
    const uint32_t Kw = static_cast<uint32_t>(w_ori.GetDim(3));

    if (KCin != Cin) {
        return ge::GRAPH_FAILED;
    }

    const uint32_t Oh = (H >= Kh) ? (H - Kh + 1) : 0u;
    const uint32_t Ow = (W >= Kw) ? (W - Kw + 1) : 0u;

    const bool hasBias = (context->GetNumInputs() >= 3) &&
                         (context->GetInputShape(2) != nullptr) &&
                         (context->GetInputShape(2)->GetOriginShape().GetShapeSize() > 0);

    // We tile by output pixel (n, oh, ow). Simple strategy: 1 pixel per tile for robust UB usage.
    const uint64_t totalPixels = static_cast<uint64_t>(N) * static_cast<uint64_t>(Oh) * static_cast<uint64_t>(Ow);
    const uint32_t tilePixels = 1;

    // Select blockDim conservatively
    uint32_t blockDim = (totalPixels == 0) ? 1u : static_cast<uint32_t>(totalPixels);
    if (blockDim > 32u) blockDim = 32u;
    if (blockDim == 0) blockDim = 1u;

    context->SetBlockDim(blockDim);

    tiling.set_n(N);
    tiling.set_cin(Cin);
    tiling.set_hin(H);
    tiling.set_win(W);
    tiling.set_cout(Cout);
    tiling.set_kh(Kh);
    tiling.set_kw(Kw);
    tiling.set_oh(Oh);
    tiling.set_ow(Ow);
    tiling.set_tilePixels(tilePixels);
    tiling.set_hasBias(hasBias ? 1u : 0u);
    tiling.set_blockDim(blockDim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *workspace_sizes = context->GetWorkspaceSizes(1);
    workspace_sizes[0] = 0;

    return ge::GRAPH_SUCCESS;
}

